toolArgs.file_text:
@* Toolbar with sort dropdown and result count label *@

<div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
    <div class="d-flex align-items-center gap-2">
        <label for="sort-select" class="form-label mb-0 fw-semibold">Sort by:</label>
        <select id="sort-select" class="form-select form-select-sm sort-select" value="@SortBy"
                @onchange="HandleSortChanged">
            <option value="price_asc">Price: Low to High</option>
            <option value="price_desc">Price: High to Low</option>
            <option value="name_asc">Name: A–Z</option>
            <option value="rating_desc">Rating: Highest</option>
        </select>
    </div>

    <span class="text-muted results-label">
        @if (TotalCount > 0)
        {
            var start = (Page - 1) * PageSize + 1;
            var end = Math.Min(Page * PageSize, TotalCount);
            @($"Showing {start}–{end} of {TotalCount} products")
        }
        else
        {
            @("No products to display")
        }
    </span>
</div>

@code {
    [Parameter]
    public string SortBy { get; set; } = "price_asc";

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int Page { get; set; } = 1;

    [Parameter]
    public int PageSize { get; set; } = 12;

    [Parameter]
    public EventCallback<string> OnSortChanged { get; set; }

    private async Task HandleSortChanged(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "price_asc";
        await OnSortChanged.InvokeAsync(value);
    }
}

