toolArgs.file_text:
@* Pagination controls: previous, page numbers, next *@

@if (TotalPages > 1)
{
    <nav aria-label="Product catalog pagination">
        <ul class="pagination justify-content-center mt-4">
            <li class="page-item @(CurrentPage <= 1 ? "disabled" : "")">
                <button class="page-link" disabled="@(CurrentPage <= 1)"
                        @onclick="@(() => GoToPage(CurrentPage - 1))">
                    Previous
                </button>
            </li>

            @foreach (var page in GetPageNumbers())
            {
                <li class="page-item @(page == CurrentPage ? "active" : "")">
                    <button class="page-link" @onclick="@(() => GoToPage(page))">
                        @page
                    </button>
                </li>
            }

            <li class="page-item @(CurrentPage >= TotalPages ? "disabled" : "")">
                <button class="page-link" disabled="@(CurrentPage >= TotalPages)"
                        @onclick="@(() => GoToPage(CurrentPage + 1))">
                    Next
